mapper.select:
SELECT orders.uuid , orders.symbol , orders.amount_close , orders.stop_price_profit , orders.stop_price_loss, orders.order_no, orders.trade_avg_price, orders.direction, orders.unit_amount , orders.state , orders.fee , orders.profit , orders.create_time , orders.deposit , orders.deposit_open , orders.close_time , orders.volume_open , orders.volume , item.name itemName, wallet.money , party.user_name, party.user_code, party.role_name FROM t_exchange_lever_order orders LEFT JOIN tz_user party ON orders.party_id = party.user_id LEFT JOIN tz_wallet wallet ON wallet.user_id = party.user_id LEFT JOIN t_item item ON orders.symbol = item.symbol WHERE 1 = 1
and party.role_name=#{rolename}
and orders.state=#{status}
and orders.order_no=#{orderNo}
and (party.user_code=#{userName} or party.user_name=#{userName})
and orders.create_time BETWEEN #{startTime} and #{endTime}
and u.user_id in
#{item}
order by orders.create_time desc
